import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"服务","description":"","frontmatter":{},"headers":[],"relativePath":"zh/api/services.md","filePath":"zh/api/services.md"}'),c={name:"zh/api/services.md"};function r(l,e,n,d,o,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="服务" tabindex="-1">服务 <a class="header-anchor" href="#服务" aria-label="Permalink to &quot;服务&quot;">​</a></h1><p>Clearance 的所有服务都位于 <code>src/Services/</code> 中，并从容器中解析，例如 <code>app(ContextService::class)</code>。它们是从控制器、策略和任务队列（job）中调用的入口层——适用于任何 <code>User</code> 模型可能未使用 <code>HasClearance</code> trait 的场景。</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code>（<code>src/Services/ContextService.php</code>）是上下文授权背后的引擎。<a href="/clearance-docs/zh/api/facade.html"><code>Clearance</code> facade</a> 和 <code>HasClearance</code> trait 都委托给它。</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p><code>resolveFor()</code> 使用三来源优先级构建其结果：</p><ol><li>上下文角色授权</li><li>全局角色授权</li><li>按上下文的覆盖（<code>forced_on</code> 追加，<code>forced_off</code> 始终优先生效）</li></ol><p>关于此优先级的概念性讲解，请参见<a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>。</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code>（<code>src/Services/RoleService.php</code>）管理上限角色。</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>方法</th><th>说明</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>设置一个上限：<code>$childRole</code> 上超出父角色权限集合的部分会被默默裁剪。如果子角色已经是父角色，或者父角色已经是子角色，则抛出 <code>ClearanceScopeViolationException</code>。</td></tr><tr><td><code>removeParent($childRole)</code></td><td>移除上限关系。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>上限只会裁剪权限——从不授予权限。一个权限宽松的父角色本身不会给子角色带来任何权限。从父角色移除一个权限会自动级联到每一个子角色。</p></div><p>关于上限角色概念的更深入介绍，请参见<a href="/clearance-docs/zh/features/roles.html">角色</a>。</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code>（<code>src/Services/PermissionService.php</code>）支撑权限面板的 CRUD。</p><p>它强制执行 <code>group-action</code> 命名约定（由 <code>enforce_naming_convention</code> 和 <code>naming_separator</code> 配置键控制），并保护 <code>clearance-*</code> 权限命名空间，使其无法在安装流程之外被创建、重命名或删除。</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code>（<code>src/Services/GuardService.php</code>）支撑看守器面板的 CRUD。</p><p>它会在应用启动时将数据库支持的看守器注入到 <code>auth.guards</code> 中，并按 <code>allowed_guard_drivers</code> 配置键进行过滤——一个未列入白名单的驱动程序会被跳过，并记录一条日志警告，而不会破坏认证配置。</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code>（<code>src/Services/MetaService.php</code>）读写 <code>clr_meta</code>（角色或看守器主体的显示名称、描述、经过净化的 SVG 图标、颜色）。它支撑设置面板的显示元数据编辑器。</p><p>SVG 图标在存储前以及每次渲染时都会经过 <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code>（一个白名单净化器）处理。</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code>（<code>src/Services/UserClearanceService.php</code>）支撑用户模块面板：</p><ul><li>全局角色分配</li><li>上下文角色分配（通过 <code>UserRoleContext</code>）</li><li>按上下文的权限覆盖（通过 <code>UserContextPermissionOverride</code>，<code>forced_on</code>/<code>forced_off</code>）</li><li>移除分配，并级联删除覆盖</li></ul><p>它强制执行一个权限提升上限：非 <code>super_admin</code> 的操作者无法修改自己的分配，也无法授予自己都不持有的权限。参见<a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>和<a href="/clearance-docs/zh/features/users.html">用户</a>。</p><h2 id="异常" tabindex="-1">异常 <a class="header-anchor" href="#异常" aria-label="Permalink to &quot;异常&quot;">​</a></h2><p>全部位于 <code>src/Exceptions/</code> 中：</p><table tabindex="0"><thead><tr><th>异常</th><th>抛出时机</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>读取到一个无效或配置错误的 <code>config/clearance.php</code> 值时（例如一个不合法的 <code>naming_separator</code>）。</td></tr><tr><td><code>ClearanceNamingException</code></td><td>在启用强制校验的情况下，一个权限名称违反了 <code>group-action</code> 命名约定时。</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>在安装流程之外，尝试修改一个受保护的 <code>clearance-*</code> 权限，或一个被锁定的资源时。</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>出现一个无效的上限角色关系（一个父角色试图成为子角色，反之亦然），或作用域不匹配时。</td></tr></tbody></table><h2 id="另请参阅" tabindex="-1">另请参阅 <a class="header-anchor" href="#另请参阅" aria-label="Permalink to &quot;另请参阅&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/api/facade.html">Facade</a>——围绕 <code>ContextService</code> 的静态调用封装。</li><li><a href="/clearance-docs/zh/api/traits-directives.html">Trait 与指令</a>——实例方法与 Blade 指令的等价形式。</li><li><a href="/clearance-docs/zh/api/artisan-commands.html">Artisan 命令</a>——<code>clearance:install</code> 和 <code>clearance:backfill</code>，它们为这些服务所操作的数据播种。</li></ul>',32)])])}const v=a(c,[["render",r]]);export{k as __pageData,v as default};
